-- W1.6 questions batch 6674/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-6e2f88c7-moex-00276', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-916530c6', 'sub-locality-6e2f88c7-01', NULL, 'essay', '乙在網路上購物，應付款項為新臺幣二萬元整。乙至超商的自動提款機
進行轉帳。當時後方有不少人等著提款，乙一時緊張便把匯款帳號中的
某個號碼輸入錯誤，該筆二萬元的金額因此被匯入甲的帳戶中。甲莫名
收到二萬元匯款，喜出望外，決定假裝不知情而不通知銀行及匯款人乙。
試問甲之刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "cdc49ac2b7a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00277', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', '公司法中對於董事的查閱權（資訊請求權）並無明文規定。試問：董事
之查閱權（資訊請求權），其法理依據為何？此一權利應否受到一定之限
制？此一權利與監察人依公司法第 218條第 1項規定之調查權，性質上
是否相同？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "86a6c8399f6f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0708", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00278', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', '甲為A公司之會計人員，其利用職務之便，盜取A公司之空白支票一紙，
另偽刻 A 公司及 A 公司負責人之印章蓋於該支票發票人欄位上，並於
票面金額填載新臺幣（下同）10萬元，受款人欄位則填上甲。甲隨後提
示該支票，支票之付款人 B 銀行因此支付票款 10 萬元。嗣後，A 公司
負責人發現公司於 B 銀行之帳戶內金額短少 10 萬元，始知 B 銀行對甲
偽開之支票加以付款一事。試問：A公司得否請求B銀行返還 10萬元？
B銀行得否依票據法第71條第2項規定：「付款人對於背書簽名之真偽，
及執票人是否票據權利人，不負認定之責。但有惡意或重大過失時，不
在此限。」進而主張其僅於有故意或重大過失時，始應負責？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "86a6c8399f6f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0708", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00279', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', '保險業依法以其資金購買公司股票時，在被投資公司之董事選舉中，保
險業有無董事選舉權、被選舉權？若保險業係經主管機關核准，辦理公
共及社會福利事業投資，在被投資公司之董事選舉中，保險業之董事選
舉權、被選舉權，有無不同？民國 110年修法前後有何不同？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "86a6c8399f6f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0708", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00280', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-d7e58de3', 'sub-locality-6e2f88c7-06', NULL, 'essay', '依海商法第 24 條規定，為海事優先權擔保之債權包括那些？同次航行
之海事優先權，其順序如何決定？其得優先受償之標的為何？（20 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "86a6c8399f6f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0708", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "商事法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00281', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '甲（住臺北市大安區）起訴主張其與乙、丙（2 人均住新北市板橋區）
共有坐落桃園市中壢區某址之A地，應有部分各三分之一，自民國107年
3 月 12 日起該地被丁（住臺北市中正區）無權占用，因乙及丙不欲對丁
起訴請求返還該地，甲故而單獨起訴請求法院命丁返還 A地予原告及其
他共有人乙、丙。試問：
如甲係向臺北地方法院起訴，該法院是否有管轄權？甲單獨起訴請求
丁返還 A地，是否具備當事人適格？如甲聲請法院裁定命乙及丙追加
為原告，法院如何處理？（30 分）
法院在審理中應否闡明原告得追加請求被告應給付因無權占用 A 地
而受有相當於租金之不當得利？而如被告丁抗辯其對 A地有租賃權，
原告則否認之，則對租賃關係存否之事實應由何人負舉證責任？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "fc99c4c9bae1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00282', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '檢察官偵查一宗槍擊命案，認為甲涉有嫌疑，但數度傳喚甲，甲均無正
當理由不到場，乃簽發拘票，交由司法警察執行拘提。雖然時間充裕，
但在未聲請搜索票下，司法警察官直接命司法警察 A、B 持拘票，前往
甲宅公寓執行拘提，視情況搜索、扣押；並於翌日報告該管檢察署檢察
官及法院。試問：下列搜索、扣押，是否合法？
司法警察 A、B 抵達甲宅，聽聞屋內有人聲，按數下門鈴無人應答，
直接破門而入。甲宅客廳空無 1人，但茶几上放置數包安非他命及吸
食器，A、B將之扣押。（10 分）
司法警察 A、B奔往陽台察看，見甲正試圖從陽台逃走，立刻拘捕甲。
隨後，由 A看守甲，B則返回屋內繼續搜索，在翻找臥房衣櫃時，發
現疑似是槍殺被害人之改造手槍及數發子彈，亦將之扣押。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "fc99c4c9bae1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00283', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-e733516d', 'sub-locality-6e2f88c7-02', NULL, 'essay', '某傷害案件之被告堅稱無罪，但第一審法院判決有罪。案經上訴二審，
審判長於調查證據完畢後，訊問被告有無意見，被告稱：「我無罪！我沒
有打人！該說的在一審都說了，已經懶得再說。」審判長聽聞後表示，
本件案情相當單純，應毋庸再進行辯論，便直接宣示辯論終結。請附理
由說明，本案之審理程序是否違法，而得以上訴救濟？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "fc99c4c9bae1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00284', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'essay', '甲向乙承租一間房屋，並簽訂書面租賃契約，其中第 9條約定：「承租人
應以善良管理人之注意保管房屋，如違反此項義務，致房屋毀損或滅失
者，應負損害賠償責任。但依約定之方法或依房屋之性質使用、收益，
致房屋有毀損或滅失者，不在此限。」甲遷入後將前面規劃為美甲工作
室，後面則作為居家使用。某日甲所有的電暖氣因過於老舊且使用時間
較長而引發火災，導致該房屋部分受損。試說明乙得否向甲請求損害賠
償。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00285', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'essay', '甲男喪偶多年，與前妻於婚姻關係存續中生有一女 A，已成年。此時，
與甲交往之乙女，多次想要與甲結婚，甲皆不答應，乙知甲想要有子嗣，
乃告知甲，其已懷有甲之子 B，甲才答應與乙依法結婚，但其實B 為乙
與丁男私通之結果。甲乙結婚後半年，B子出生。A於偶然間得知 B與
甲無血緣關係，而為乙與丁所生。試問：
A 可否撤銷甲乙之婚姻？甲若知悉 B 無自己之血緣後逾 3 個月，可
否提起撤銷婚姻之訴訟？（12 分）
若婚姻撤銷之訴獲勝訴判決後，甲因過勞病發去世，留下財產新臺幣
1200萬元，應由何人繼承？（13分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "a4b613a63dd0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
